import React, { useState, useEffect } from 'react';
import { useTranslation } from '../hooks/useTranslation';
import SectionLabel from './SectionLabel';

const Certificates = () => {
  const { t } = useTranslation();
  const [activeFilter, setActiveFilter] = useState('fatec');
  const [currentCert, setCurrentCert] = useState(null);

  const certificates = [

    {
      id: 'webdev',
      title_key: 'certificate_webdev_title',
      institution: 'Coursera - Johns Hopkins University',
      image: 'assets/img/services/Web-Development.jpg',
      description_key: 'certificate_webdev_desc',
      skills: ['CSS', 'Bootstrap', 'JavaScript', 'HTML5', 'AJAX'],
      category: 'frontend',
      date: '2024',
      credential: 'Curso Online'
    },
    {
      id: 'powerbi',
      title_key: 'certificate_powerbi_title',
      institution: 'Data Science Academy',
      image: 'assets/img/services/Power-BI.jpg',
      description_key: 'certificate_powerbi_desc',
      skills: ['Microsoft Power BI', 'Microsoft Excel', 'Dashboards', 'Data Analysis', 'Spreadsheet Management'],
      category: 'data',
      date: '2024',
      credential: 'Curso Online'
    },
    {
      id: 'database',
      title_key: 'certificate_database_title',
      institution: 'IFSul - Plataforma Mundi',
      image: 'assets/img/services/Banco-de-Dados.jpg',
      description_key: 'certificate_database_desc',
      skills: ['Database', 'SQL', 'Spreadsheet Management', 'Data Analysis'],
      category: 'data',
      date: '2024',
      credential: 'Curso Online'
    },
    {
      id: 'logic',
      title_key: 'certificate_logic_title',
      institution: 'DIO - Digital Innovation One',
      image: 'assets/img/services/Logica-de-Programacao.jpg',
      description_key: 'certificate_logic_desc',
      skills: ['JavaScript', 'Git', 'GitHub', 'Logic'],
      category: 'frontend',
      date: '2024',
      credential: 'Curso Online'
    },
    {
      id: 'react',
      title_key: 'certificate_react_title',
      institution: 'Cursa',
      image: 'assets/img/services/react.png',
      description_key: 'certificate_react_desc',
      skills: ['React', 'API Rest', 'JavaScript'],
      category: 'frontend',
      date: '2024',
      credential: 'Curso Online'
    },
    {
      id: 'java',
      title_key: 'certificate_java_title',
      institution: 'Rocketseat',
      image: 'assets/img/services/Java.png',
      description_key: 'certificate_java_desc',
      skills: ['Java', 'Spring Boot', 'API Rest', 'Database', 'Lombok'],
      category: 'backend',
      date: '2024',
      credential: 'Curso Online'
    }
  ];

  const filters = [
    { key: 'frontend', label: 'Front-end', icon: 'bi-window' },
    { key: 'backend', label: 'Back-end', icon: 'bi-server' },
    { key: 'data', label: 'Dados', icon: 'bi-bar-chart' }
  ];

  const getCertByFilter = (filter) => {
    if (filter === 'fatec') {
      return certificates.find(c => c.id === 'fatec');
    }
    const filtered = certificates.filter(c => c.category === filter && c.id !== 'fatec');
    return filtered[0] || certificates[0];
  };

  useEffect(() => {
    setCurrentCert(getCertByFilter(activeFilter));
  }, [activeFilter]);

  const [modalImage, setModalImage] = useState(null);

  const openImageModal = (imageSrc) => {
    setModalImage(imageSrc);
    document.body.style.overflow = 'hidden';
  };

  const closeImageModal = () => {
    setModalImage(null);
    document.body.style.overflow = '';
  };

  return (
    <section id="service-details" className="service-details section">
      <div className="section-glow"></div>
      <div className="section-waves"></div>
      <div className="section-orbs">
        <div className="orb orb-1"></div>
        <div className="orb orb-2"></div>
        <div className="orb orb-3"></div>
      </div>

      <div className="container">
        <SectionLabel sectionId="service-details" />
        <div className="section-title" data-aos="fade-up">
          <h2 data-translate="menu_certificates">Certificados</h2>
        </div>
      </div>

      <div className="container">
        <div className="certificates-showcase">
          <div className="certificates-sidebar">
            {filters.map(filter => (
              <button
                key={filter.key}
                className={`certificates-sidebar-btn ${activeFilter === filter.key ? 'active' : ''}`}
                onClick={() => setActiveFilter(filter.key)}
              >
                <i className={`bi ${filter.icon}`}></i>
                <span>{filter.label}</span>
              </button>
            ))}
          </div>

          <div className="certificates-showcase-content">
            {currentCert && (
              <div className="certificate-showcase-card" data-aos="fade-up" data-aos-delay="100">
                <div className="certificate-showcase-image" onClick={() => openImageModal(currentCert.image)}>
                  <img src={currentCert.image} alt={currentCert.title_key} />
                  <div className="certificate-image-overlay">
                    <button className="image-view-btn" onClick={(e) => {
                      e.stopPropagation();
                      openImageModal(currentCert.image);
                    }}>
                      <i className="bi bi-zoom-in"></i>
                    </button>
                  </div>
                  <div className="certificate-showcase-badge">
                    <i className="bi bi-award-fill"></i>
                  </div>
                </div>

                <div className="certificate-showcase-details">
                  <div className="certificate-showcase-header">
                    <h3 className="certificate-showcase-title" data-translate={currentCert.title_key}>
                      {t(currentCert.title_key)}
                    </h3>
                    <div className="certificate-meta">
                      <span className="certificate-date">
                        <i className="bi bi-calendar"></i>
                        {currentCert.date}
                      </span>
                      <span className="certificate-credential">
                        <i className="bi bi-patch-check"></i>
                        {currentCert.credential}
                      </span>
                    </div>
                    <p className="certificate-showcase-institution">
                      <i className="bi bi-building"></i>
                      {currentCert.institution}
                    </p>
                  </div>

                  <div className="certificate-showcase-skills">
                    <div className="skills-title">
                      <i className="bi bi-check-circle-fill"></i>
                      <span data-translate="certificate_skills_developed">
                        {t('certificate_skills_developed')}
                      </span>
                    </div>
                    <div className="skills-tags">
                      {currentCert.skills.map((skill, idx) => {
                        const translationKey = `skill_${skill.toLowerCase().replace(/\s+/g, '_')}`;
                        return (
                          <span key={idx} className="skill-tag">
                            {t(translationKey) !== translationKey ? t(translationKey) : skill}
                          </span>
                        );
                      })}
                    </div>
                  </div>

                  <div className="certificate-showcase-description">
                    <p data-translate={currentCert.description_key}>{t(currentCert.description_key)}</p>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {modalImage && (
        <div className="image-modal" onClick={closeImageModal}>
          <div className="image-modal-content" onClick={(e) => e.stopPropagation()}>
            <button className="image-modal-close" onClick={closeImageModal}>
              <i className="bi bi-x-lg"></i>
            </button>
            <img src={modalImage} alt="Certificado" />
          </div>
        </div>
      )}
    </section>
  );
};

export default Certificates;
